    for p in extract_projects_started_spring_2022(d.get('text','')):
        unique.add(p)

result = {'projects_started_spring_2022': sorted(unique), 'count': len(unique)}
print('__RESULT__:')
print(json.dumps(result, ensure_ascii=False))"}

